import { useCurrentFrame, interpolate, Easing } from "remotion";

type LineChartProps = { fps: number };

// Simulated latency data points (ms)
const DATA = [58, 42, 67, 38, 44, 51, 39, 43, 36, 48, 42, 55, 41, 38, 45, 40, 37, 44, 42, 39];

const CHART_W = 1600;
const CHART_H = 560;
const PAD = { top: 40, right: 60, bottom: 60, left: 80 };
const INNER_W = CHART_W - PAD.left - PAD.right;
const INNER_H = CHART_H - PAD.top - PAD.bottom;

const MIN_VAL = 30;
const MAX_VAL = 80;

function toX(i: number) {
  return PAD.left + (i / (DATA.length - 1)) * INNER_W;
}
function toY(v: number) {
  return PAD.top + ((MAX_VAL - v) / (MAX_VAL - MIN_VAL)) * INNER_H;
}

const LINE_PATH = DATA.map((v, i) => `${i === 0 ? "M" : "L"} ${toX(i)} ${toY(v)}`).join(" ");

const AREA_PATH =
  LINE_PATH +
  ` L ${toX(DATA.length - 1)} ${PAD.top + INNER_H} L ${toX(0)} ${PAD.top + INNER_H} Z`;

export const LineChart: React.FC<LineChartProps> = ({ fps }) => {
  const frame = useCurrentFrame();

  const drawProgress = interpolate(frame, [15, 120], [0, 1], {
    extrapolateRight: "clamp",
    extrapolateLeft: "clamp",
    easing: Easing.inOut(Easing.cubic),
  });

  const areaOpacity = interpolate(frame, [60, 100], [0, 0.25], { extrapolateRight: "clamp" });

  // Approximate total path length for stroke-dasharray animation
  const approxLength = 2200;
  const dashOffset = approxLength * (1 - drawProgress);

  const gridLines = [40, 50, 60, 70, 80];

  return (
    <div style={{ flex: 1, background: "#1E293B", borderRadius: 16, border: "1px solid #334155", padding: 24 }}>
      <svg width="100%" viewBox={`0 0 ${CHART_W} ${CHART_H}`}>
        <defs>
          <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#38BDF8" stopOpacity="0.6" />
            <stop offset="100%" stopColor="#38BDF8" stopOpacity="0" />
          </linearGradient>
          <linearGradient id="lineGrad" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="#818CF8" />
            <stop offset="100%" stopColor="#38BDF8" />
          </linearGradient>
        </defs>

        {/* Grid lines */}
        {gridLines.map((v) => (
          <g key={v}>
            <line
              x1={PAD.left}
              y1={toY(v)}
              x2={PAD.left + INNER_W}
              y2={toY(v)}
              stroke="#334155"
              strokeWidth={1}
              strokeDasharray="6 6"
            />
            <text
              x={PAD.left - 12}
              y={toY(v) + 5}
              textAnchor="end"
              fill="#64748B"
              fontSize={20}
            >
              {v}
            </text>
          </g>
        ))}

        {/* X-axis labels */}
        {DATA.map((_, i) =>
          i % 4 === 0 ? (
            <text
              key={i}
              x={toX(i)}
              y={PAD.top + INNER_H + 36}
              textAnchor="middle"
              fill="#64748B"
              fontSize={18}
            >
              {`${i * 3}s`}
            </text>
          ) : null
        )}

        {/* Area fill */}
        <path d={AREA_PATH} fill="url(#areaGrad)" opacity={areaOpacity} />

        {/* Animated line */}
        <path
          d={LINE_PATH}
          fill="none"
          stroke="url(#lineGrad)"
          strokeWidth={4}
          strokeLinecap="round"
          strokeLinejoin="round"
          strokeDasharray={approxLength}
          strokeDashoffset={dashOffset}
        />

        {/* Dot on latest point */}
        {drawProgress > 0.95 && (
          <circle
            cx={toX(DATA.length - 1)}
            cy={toY(DATA[DATA.length - 1])}
            r={8}
            fill="#38BDF8"
            stroke="#0F172A"
            strokeWidth={3}
          />
        )}

        {/* Y-axis label */}
        <text
          x={20}
          y={PAD.top + INNER_H / 2}
          textAnchor="middle"
          fill="#64748B"
          fontSize={18}
          transform={`rotate(-90, 20, ${PAD.top + INNER_H / 2})`}
        >
          Latency (ms)
        </text>
      </svg>
    </div>
  );
};

