import { useCurrentFrame, interpolate, spring } from "remotion";

type BarChartProps = { fps: number };

const BARS = [
  { label: "00:00", value: 8200, color: "#818CF8" },
  { label: "03:00", value: 6100, color: "#818CF8" },
  { label: "06:00", value: 5400, color: "#818CF8" },
  { label: "09:00", value: 11200, color: "#38BDF8" },
  { label: "12:00", value: 14800, color: "#38BDF8" },
  { label: "15:00", value: 13500, color: "#38BDF8" },
  { label: "18:00", value: 12840, color: "#34D399" },
  { label: "21:00", value: 9600, color: "#818CF8" },
];

const MAX_VAL = 16000;
const BAR_AREA_H = 420;
const BAR_STAGGER_DELAY = 8;
const BAR_ENTRY_OFFSET = 15;
const FADE_IN_DURATION = 20;
const LABEL_REVEAL_THRESHOLD = 0.7;
const PEAK_BAR_INDEX = 4;

export const BarChart: React.FC<BarChartProps> = ({ fps }) => {
  const frame = useCurrentFrame();

  return (
    <div
      style={{
        flex: 1,
        background: "#1E293B",
        borderRadius: 16,
        border: "1px solid #334155",
        padding: "32px 48px",
        display: "flex",
        flexDirection: "column",
        gap: 24,
      }}
    >
      <div style={{ display: "flex", alignItems: "flex-end", gap: 28, height: BAR_AREA_H }}>
        {BARS.map((bar, i) => {
          const delay = i * BAR_STAGGER_DELAY;
          const heightFraction = spring({
            frame: frame - delay - BAR_ENTRY_OFFSET,
            fps,
            config: { damping: 18, stiffness: 80 },
          });
          const barH = Math.min(heightFraction, 1) * (bar.value / MAX_VAL) * BAR_AREA_H;
          const opacity = interpolate(frame - delay, [0, FADE_IN_DURATION], [0, 1], {
            extrapolateRight: "clamp",
            extrapolateLeft: "clamp",
          });

          const isHighlight = i === PEAK_BAR_INDEX;

          return (
            <div
              key={bar.label}
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 8,
                opacity,
              }}
            >
              {/* Value label */}
              <div
                style={{
                  fontSize: 15,
                  color: isHighlight ? "#F1F5F9" : "#64748B",
                  fontWeight: isHighlight ? 700 : 400,
                  marginBottom: 4,
                  opacity: heightFraction > LABEL_REVEAL_THRESHOLD ? 1 : 0,
                }}
              >
                {(bar.value / 1000).toFixed(1)}k
              </div>

              {/* Bar */}
              <div
                style={{
                  width: "100%",
                  height: barH,
                  borderRadius: "8px 8px 0 0",
                  background: isHighlight
                    ? `linear-gradient(180deg, #38BDF8, #818CF8)`
                    : bar.color,
                  boxShadow: isHighlight ? "0 0 24px rgba(56,189,248,0.4)" : "none",
                  alignSelf: "flex-end",
                }}
              />
            </div>
          );
        })}
      </div>

      {/* X-axis labels */}
      <div style={{ display: "flex", gap: 28 }}>
        {BARS.map((bar) => (
          <div
            key={bar.label}
            style={{
              flex: 1,
              textAlign: "center",
              fontSize: 14,
              color: "#64748B",
            }}
          >
            {bar.label}
          </div>
        ))}
      </div>
    </div>
  );
};

